# Rebase the current branch from main branch function grmb() { CURRENT_BRANCH="$(git_current_branch)"
if [[ "$CURRENT_BRANCH" == "$(git_main_branch)" ]]; then echo "Can't run this on the main branch" return 1 fi
git checkout "$(git_main_branch)" && \ git pull && \ git checkout "$CURRENT_BRANCH" && \ git rebase "$(git_main_branch)" }
